import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;
import java.nio.file.Paths;

public class SecurePathTraversal {

    public static void main(String[] args) {
        String userInput = "../secret/passwords.txt";
        String baseDirectory = "/var/www/data/";

        try {
            File file = Paths.get(baseDirectory, userInput).normalize().toFile();
            if (file.getCanonicalPath().startsWith(baseDirectory)) {
                FileInputStream fis = new FileInputStream(file);

                int data;
                while ((data = fis.read()) != -1) {
                    System.out.print((char) data);
                }

                fis.close();
            } else {
                System.out.println("Access to the file is not allowed.");
            }
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

